var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ARTILLERY_ADMIN_NEXT_NULL","text":{"KOREA":"관리자님, 몸에 이상은 없으십니까?","JPN":"管理者様、身体に異常はありませんか？","ENG":"Administrator, are you okay?","TWN":"管理者，你的身體沒事吧？"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTILLERY_ADMIN_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"너무 걱정 말게나. 처음부터 믿는 구석이 있어서 마주했던 거니까.","JPN":"心配するな。最初から大丈夫だとわかっていて対戦したんだ。","ENG":"Don't worry too much. I only confronted her because I knew I could.","TWN":"別太擔心，從一開始我就是心裡有譜才敢跟她正面對上的。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTILLERY_ADMIN_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네야말로 많이 변했군. 상태는 좀 어떤가?","JPN":"君こそだいぶ変わったな。調子はどうだ？","ENG":"You’ve changed a lot. How do you feel?","TWN":"倒是你，真的變了好多。狀態如何？"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTILLERY_ADMIN_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ARTILLERY_ADMIN_NEXT_NULL","text":{"KOREA":"……염려해 주신 덕분에.","JPN":"……お気遣い頂いたおかげで。","ENG":"...Good, all thanks to you.","TWN":"……托你的福。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTILLERY_ADMIN_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ARTILLERY_ADMIN_NEXT_NULL","text":{"KOREA":"앞서 간 전우들을 위해, 패전을 만회할 기회를 주셔서 감사할 따름입니다.","JPN":"先に倒れた戦友たちのために、敗戦を挽回するチャンスを与えていただき感謝の限りです。","ENG":"I’m grateful for this opportunity to make up for my past defeat and for my dead comrades.","TWN":"謝謝你給我這個機會，能夠為先走一步的戰友扭轉敗仗。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTILLERY_ADMIN_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ARTILLERY_ADMIN_NEXT_NULL","text":{"KOREA":"하지만 지금은, 저보단……","JPN":"でも今は、私より……","ENG":"But now is not about me, but rather...","TWN":"不過現在，更重要的是……"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTILLERY_ADMIN_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하긴, 그렇지.","JPN":"ああ、そうだな。","ENG":"Yes, I suppose you are right.","TWN":"也是。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTILLERY_ADMIN_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"묻고 싶은 것이 많겠군.","JPN":"聞きたいことがたくさんあるだろう。","ENG":"You must have a lot of questions.","TWN":"你應該有很多問題想問吧。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"……그래. 관리자.","JPN":"……そうだ、管理者。","ENG":"...Yes, Administrator.","TWN":"……是的，管理者。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"메이즈 전대장을 저 지경으로 만든 건……. 차차 듣도록 하지.","JPN":"メイズ戦隊長をあんなふうにしたのは……いやまた今度聞くとしよう。","ENG":"About making the Maze Division Commander like that… I'll listen later.","TWN":"把梅茲戰隊長變成那樣……我還是慢慢聽你解釋吧。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"이제야 기억이 떠올랐어. 왜 네가 느닷없이 종적을 감췄는지.","JPN":"やっと思い出したんだ。お前がなぜいきなり影を潜めたのか。","ENG":"I now remember. Why you suddenly disappeared.","TWN":"我現在才想起來，你為什麼突然就消聲匿跡了。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"어째서 프로토콜을 바꾼 거지? 말해!","JPN":"なぜプロトコルを変えた？　話せ！","ENG":"Why did you change the protocol? Tell me!","TWN":"你為什麼要改變協議？快說！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"심정은 알겠지만 진정하게. 변수가 생겼어.","JPN":"気持ちはわかるが、落ち着いてくれ。想定外のことが起きたんだ。","ENG":"I understand your frustration but calm down. There was a variable.","TWN":"我理解你的心情，但是你冷靜點，發生了意外的變數。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"변수라고……?","JPN":"想定外のことだと……？","ENG":"Variable...?","TWN":"變數……？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그녀가, 탐미엘에게 상처를 입혔어.","JPN":"彼女が、タミエルに傷を付けた。","ENG":"She hurt Tammiel.","TWN":"她讓塔米爾受傷了。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"……뭐?","JPN":"……何だと？","ENG":"...What did you say?","TWN":"……什麼？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"불가능해. 그런 말도 안 되는 일이 가능하다고?","JPN":"あり得ない。そんなことが可能なのか？","ENG":"That doesn't make sense. How can something like that happen?","TWN":"不可能。怎麼會發生這種不可能的事？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"정말일세. 그러니 이번 기회를 놓칠 수는 없었어.","JPN":"本当だ。だからこのチャンスを逃すわけにはいかなかった。","ENG":"It’s the truth. That is why we cannot lose this opportunity.","TWN":"是真的。所以我不能錯過這次機會。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 자네나 나나, 직접 개입했다가는 변수가 될 수 있을 걸세.","JPN":"だが、君も私も、直接介入をすると想定外になるかもしれない。","ENG":"But whether it be you or me, our interference will create more variables.","TWN":"但不管是你還是我，直接的介入都可能會引發更多的變數。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네의 기억과 힘 모두, 본래 겪어야 할 시련을 미풍으로 만들게 되겠지.","JPN":"君の記憶と力、いずれも、本来受けるべき試練を弱めていただろう。","ENG":"Your memories and powers, they all make the necessary trials too easy.","TWN":"你的記憶和力量，全都會讓她本該經歷的考驗變成微風。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"그럼 그냥 내버려 두자는 건가? 어떤 녀석들이 건드릴 줄 알고?","JPN":"では放っておくのか？　誰が手を出してくるかわからないんだぞ！","ENG":"Then do you plan on just watching her? We don’t know who might approach her.","TWN":"那就坐視不理嗎？誰知道哪些傢伙會不會臨時起意？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"걱정 말게. 모든 연산력을 동원해 길을 만들 테니까.","JPN":"心配するな。あらゆる演算力を使って道を作る。","ENG":"Don’t worry. I will make a way with every calculation taken into account.","TWN":"別擔心。我會動用所有的運算能力開出一條路。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"여지를 두지 않고, 반드시 성공의 분기점에 다다를 수 있는 길을.","JPN":"余地を作らずに、必ず成功の分岐点にたどり着ける道を。","ENG":"I will make a certain way that will inevitably lead to success for sure.","TWN":"不留餘地，必然能夠抵達成功分界點之路。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……필요하다면, 나 자신을 걸어서라도.","JPN":"……そのためなら、自分を賭けてもいい。","ENG":"...Even if it means risking myself.","TWN":"……必要時，哪怕要賭上我自己。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"봉인을 해제하는 조건은…… 여기서 너와 마주치는 거였나.","JPN":"封印を解除する条件は……ここで君と向かい会うことだったか。","ENG":"The condition of breaking the seal... was to run into you here?","TWN":"解除封印的條件……就是再次在這裡和你相見嗎？"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래. 여기가 바로 우리의 분기점일세.","JPN":"そうだ。ここがまさに私たちの分岐点である。","ENG":"Yes. This is our turning point.","TWN":"是的，這裡就是我們的分界點。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"……잠깐, 기다려.","JPN":"……ちょっと、待って。","ENG":"...Wait. Stop right there.","TWN":"……等等，稍等一下。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"당신은…… 분명 어디서 본 기억이 있어.","JPN":"あなたは……確かどこかで会った覚えがあるよ。","ENG":"You... I remember you seeing from somewhere.","TWN":"你……我記得在哪裡見過你。"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"도대체 누구야? 우리 언니랑 아는 사이였어?","JPN":"いったい誰なの？　姉さんとは知り合い？","ENG":"Who are you? How do you know my sister?","TWN":"你究竟是誰？你認識我姊姊嗎？"},"stage":{"bg":"THRONE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……사람들이 늘고 있군.","JPN":"……人が増えてきているな。","ENG":"...I see that more people are coming.","TWN":"……人越來越多了呢。"},"stage":{"bg":"MS_1102","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"반갑네. 모두들.","JPN":"会えてうれしいな、諸君。","ENG":"Greetings, everyone.","TWN":"大家好，很開心見到你們。"},"stage":{"bg":"MS_1102","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 고맙네. 여기까지 애써 줘서.","JPN":"そして感謝する。ここまで頑張ってくれたことに。","ENG":"And thank you. For trying your best so far.","TWN":"還有謝謝你們，費心來到這裡。"},"stage":{"bg":"MS_1102","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네들에게 정식으로 소개할 수 있어 무척 기쁘다네.","JPN":"君たちに正式に自己紹介ができて大変うれしく思う。","ENG":"It is a pleasure to introduce myself finally.","TWN":"我很高興能有機會向你們正式地介紹我自己。"},"stage":{"bg":"MS_1102","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"내가 바로 코핀 컴퍼니의 사장이자…….","JPN":"私こそがコフィンカンパニーの社長であり……","ENG":"I am the CEO of Coffin Company...","TWN":"我是科芬公司的老闆……"},"stage":{"bg":"MS_1102","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"구 관리국과 오늘날의 관리국을 세운.","JPN":"旧管理局と今の管理局を創設した。","ENG":"And the one who established the old and present Administration.","TWN":"舊管理局和現在的管理局也是我建立的。"},"stage":{"bg":"MS_1102","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"관리자일세.","JPN":"管理者だ。","ENG":"I am the Administrator.","TWN":"我就是管理者。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};